INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$37138c1a-42eb-4202-bd31-df0c1bf5cf49$tag$, $tag$2026021000545$tag$, $tag$Julliana Costa (5583987621025)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, boa tarde.  Eu fiz o pagamento da matricula, mas não estou mais encontrando o contrato para fazer a assinatura digital. Pode me ajudar?","time":"10/02/2026 16:28:00"},{"role":"client","text":"🌟 Boa tarde Julliana Costa! Que alegria ter você aqui com a gente! 🙌","time":"10/02/2026 16:28:02"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"10/02/2026 16:28:06"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"10/02/2026 16:28:10"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"10/02/2026 16:28:17"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"10/02/2026 16:28:37"},{"role":"client","text":"Olá! Julliana Costa!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"10/02/2026 16:28:38"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"10/02/2026 16:28:42"},{"role":"client","text":"Falar com um atendente","time":"10/02/2026 16:29:02"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"10/02/2026 16:29:03"},{"role":"client","text":"Matricula na faculdade de direito","time":"10/02/2026 16:29:34"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"11/02/2026 11:33:20"},{"role":"agent","text":"*Karina Pimentel:* *Bacharelado em Direito*\n\n*GRADUAÇÃO COM COSMOVISÃO CRISTÃ*\nValorização do Direito clássico, sem viés ideológico, o Direito tratado numa cosmovisão cristã.\n\n*NOTA MÁXIMA NO MEC*\nGraduação com a maior avaliação junto ao MEC, conceito 05 estrelas ( *bit.ly/3LlEgJS* ) com duração de 5 anos. \n\n*PRÁTICA JURÍDICA*\nÚnico curso no Brasil com vivência de prática jurídica do primeiro ao décimo período.\n\n*NÚCLEO*\nPrimeiro e único núcleo de prática jurídica em Lei Geral de Proteção de Dados (LGPD).\n\n*VOCAÇÃO*\nEspecialização durante a graduação com disciplinas optativas nas áreas: \n\na) Serviço Público; \nb) Advocacia Empreendedora; \nc) Academia\n\n*BIBLIOTECA DIGITAL*\nRevista dos Tribunais online e a Biblioteca Digital Proview da Revista dos Tribunais. Kindles com assinatura Unlimited.\n\n*AULAS PRESENCIAIS*\nDe segunda à sexta, das 19h às 22h - goo.gl/maps/tb5occMvgJGHsjwz9.\n\n  Segue a matriz curricular do curso de Direito *bit.ly/3SpepqX*\n\nA mensalidade da Graduação em Direito está R$ 1.407,95. \n\n🤩 Estamos com uma condição excepcional, desconto de 60% na pontualidade durante toda graduação que ficará o valor de R$ 563,18.\n\nNão há taxa de matrícula, sendo a primeira mensalidade paga no ato da inscrição, e as demais mensalidades pagas até o dia 10 de cada mês.\n\n🌟 Valor promocional: (Semestralidade R$ 3.379,08).\n⚠️ Valor mensal está sujeito a mudança de acordo a data de matrícula:\n\n Matrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 675,81 = R$ 3.379,08\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 844,77 = R$ 3.3.79,08\n\nInício das aulas em Fevereiro de 2026 📚📖💻","time":"11/02/2026 11:35:13","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Oi Karina, já tinha falado contigo. Fiz o pagamento do pix. Entrei com a opção de uso nota do ENEM","time":"11/02/2026 13:42:46"},{"role":"agent","text":"*Karina Pimentel:* Boa tarde!","time":"11/02/2026 15:19:58","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Deu tudo certo minha irmã?","time":"11/02/2026 15:20:09","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Deu sim m. Me diz uma coisa, nao estou conseguindo ver a parte do contrato.","time":"11/02/2026 16:18:28"},{"role":"client","text":"Como faço?","time":"11/02/2026 16:18:42"},{"role":"agent","text":"*Karina Pimentel:* Não foi enviado?","time":"11/02/2026 16:20:15","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/698cd6ccf9628a94b400c618)","time":"11/02/2026 16:21:48","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/698cdb9f80105b51620c751b)","time":"11/02/2026 16:42:23"},{"role":"client","text":"Deu certo!! Obrigada!!","time":"11/02/2026 16:58:38"},{"role":"client","text":"Só mais uma coisa, quando começam as aulas?","time":"11/02/2026 17:27:59"},{"role":"agent","text":"*Karina Pimentel:* Aula inaugural foi sexta-feira.","time":"11/02/2026 17:39:16","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Oficialmente será na segunda!","time":"11/02/2026 17:39:40","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* De segunda à sexta, das 19h às 22h - goo.gl/maps/tb5occMvgJGHsjwz9.","time":"11/02/2026 17:39:53","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Obrigadaaaaa","time":"11/02/2026 17:59:16"},{"role":"agent","text":"*Karina Pimentel:* De nada!","time":"11/02/2026 18:22:53","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Boas aulas e seja bem vinda!","time":"11/02/2026 18:23:04","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Deus abençoe!","time":"11/02/2026 18:23:12","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Amém Karina!","time":"11/02/2026 18:23:36"},{"role":"client","text":"Atendimento Finalizado!\n\nJulliana Costa, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"11/02/2026 18:38:25"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"11/02/2026 18:38:26"},{"role":"client","text":"5","time":"11/02/2026 18:38:41"},{"role":"client","text":"👉 Se quiser, você também pode deixar um comentário:\n✍️ \"O que podemos melhorar para te atender ainda melhor?\"\n\nDeseja deixar um comentário?\n\n1 - Sim\n2 - Não\n","time":"11/02/2026 18:38:43"},{"role":"client","text":"Julliana Costa, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n\nAté mais!","time":"11/02/2026 18:53:43"}]$tag$, $tag$2026-02-10 16:28:00+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 11, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$,