INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$98b83871-b6d4-40a6-b702-abcac488f255$tag$, $tag$2026021100180$tag$, $tag$Bianca (5561981203971)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Bom dia!\nSobre o curso Psicoteologia","time":"11/02/2026 09:54:02"},{"role":"client","text":"🌟 Bom dia Bianca! Que alegria ter você aqui com a gente! 🙌","time":"11/02/2026 09:54:03"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"11/02/2026 09:54:07"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"11/02/2026 09:54:11"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"11/02/2026 09:54:15"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"11/02/2026 09:54:20"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"11/02/2026 09:54:26"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"11/02/2026 09:54:27"},{"role":"client","text":"Sim, concordo","time":"11/02/2026 09:54:39"},{"role":"client","text":"✅ Obrigado, Bianca! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"11/02/2026 09:54:40"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"11/02/2026 09:54:44"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"11/02/2026 09:58:31"},{"role":"client","text":"Olá! Bianca!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"11/02/2026 09:58:32"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"11/02/2026 09:58:36"},{"role":"client","text":"Saber sobre os cursos","time":"11/02/2026 10:00:06"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"11/02/2026 10:00:11"},{"role":"client","text":"Pós-Graduação","time":"11/02/2026 10:02:45"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"11/02/2026 10:02:49"},{"role":"client","text":"Psicoteologia","time":"11/02/2026 10:03:34"},{"role":"client","text":"Integra áreas do cuidado integral com a Teologia para compreender o ser humano de maneira profunda.\n 🧠 Corpo, mente e espírito.\n 📚 Forma profissionais preparados para oferecer cuidado emocional e espiritual com profundidade acadêmica e sensibilidade cristã.\n📌 Voltado para profissionais da área da saúde, teologia, aconselhamento, capelania e interessados na temática.\n🎓 Professores mestres e doutores na área.\n\n💻 Estudo online (100% EAD) e contextualizado\n","time":"11/02/2026 10:03:34"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"11/02/2026 10:03:38"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"11/02/2026 10:03:58"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"11/02/2026 10:03:59"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"11/02/2026 14:35:10"},{"role":"agent","text":"*Thayanne Sales:* Olá Boa tarde! Tudo bom?\nQue alegria falar com você! 👋🏼\n\nVou lhe enviar as informações sobre o curso","time":"11/02/2026 14:35:50","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Thayanne Sales:* *PÓS-GRADUAÇÃO EM PSICOTEOLOGIA*\n\nNOTA MÁXIMA NO MEC\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\nDURAÇÃO\nO curso tem duração de 16 meses.\n\nCARGA HORÁRIA\n560 horas\n\nDISCIPLINAS\n13 disciplinas \n\nAULAS\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\nAVALIAÇÕES\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\nNÃO É NECESSÁRIO TCC\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"11/02/2026 14:36:03","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Oi Thayane, agradeço!","time":"11/02/2026 14:36:07"},{"role":"agent","text":"*Thayanne Sales:* Disciplinas e Professores:\n\nMódulos Psicoteologia Teórica\n\n1 Introdução à Psicoteologia - Dr. Sérgio Queiroz\n2 Introdução à Cosmovisão e Filosofia cristã - Dr. Bruno Ribeiro\n3 Fundamentos Históricos e Filosóficos da Psicoteologia - Dr. Josemar Bandeira\n4 Psicoteologia Cristã Ortodoxa - Dr. Sérgio Queiroz\n\nMódulos Psicoteologia Aplicada\n\n5 Correntes Contemporâneas das Psicoterapias - Ms. Fabiana Souza /\nDra. Rebecca Athayde\n6 Psicoterapia Tomista I – Introdução à Psicoterapia Tomista, Emoções e paixões. Dr. Andrei Alves\n7 Psicoterapia Tomista II – Psicopatologias da alma e formação da personalidade - Dr. Andrei Alves /\nMs. Daniel Ouriques\n8 Introdução a ciência da felicidade - Ms. Alessandra Magalhães\n9 Terapia Cognitivo Comportamental em Psicoteologia - Dra. Cyntia Diógenes / Ms. Alessandra Magalhães /\nEsp. Juliana Araújo\n10 Logoterapia: sentido da vida e Psicoteologia - Dr. Alisson de Meneses Pontes\n11 Neurociências, psicoterapia do trauma e fé cristã - Esp. Aender Borba / Esp. Ramon Medeiros\n12 Psicoteologia do Aconselhamento Bíblico - Dr. Saulo Ribeiro - Ms. Gabriela Rique\n\nMódulos Psicoteologia Experimental\n\n13 Metodologia da pesquisa em Psicoteologia - Ms. Raphael Falcão","time":"11/02/2026 14:36:12","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:*  O valor de investimento na Pós-graduação em Psicoteologia será de: 16 mensalidades de R$ 487,00.\n\n\nA primeira mensalidade é paga no ato da matrícula, e as demais mensalidades são pagas no dia 10 dos meses subsequentes ao início das aulas, que está previsto para Março/2026.\n\n📌 Realize sua matrícula no link: https://bit.ly/SejaFICV\nNa opção \"Sou interessado\"\n\n📝 Após preencher seus dados, você receberá 2 e-mails, um com o Pagamento da primeira parcela e o outro com o Contrato Educacional para sua assinatura eletrônica.","time":"11/02/2026 14:36:20","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"E sobre o desconto para as primeiras matrículas?\nTerminou?","time":"11/02/2026 14:41:20"},{"role":"agent","text":"*Thayanne Sales:* A campanha de desconto muda todo mês ","time":"11/02/2026 14:56:53","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Deixa eu verificar com a direção o que consigo de desconto para você","time":"11/02/2026 14:57:12","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Momento","time":"11/02/2026 14:57:17","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* Consegui especialmente para você uma condição exclusiva de 50% de desconto e as mensalidades  ficarão por apenas R$ 239,58 \n\n*Mas lembrando que o desconto é de pontualidade para pagamentos que sejam realizados até o dia 10 de cada mês. Caso algum mês você pague fora desse período, perderá o desconto de pontualidade.\n\nVamos prosseguir com a sua matricula?","time":"11/02/2026 15:12:10","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"Arquivo de áudio | (https://igrejabatista.widechat.com.br/config/storage/view/698cca5643df92bc300dcc95)","time":"11/02/2026 15:28:38","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Ok Thayanne!\nTenho que fazer isso hoje?\nOu tenho até amanhã?","time":"11/02/2026 15:30:15"},{"role":"agent","text":"*Thayanne Sales:* O vencimento vai para o dia 13/02, mas lembrando que sua matricula só efetiva depois do pagamento","time":"11/02/2026 15:40:30","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Entendi","time":"11/02/2026 15:41:02"},{"role":"client","text":"Atendimento Finalizado!\n\nBianca, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"12/02/2026 15:52:38"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"12/02/2026 15:52:39"},{"role":"client","text":"Bianca, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"12/02/2026 16:07:41"}]$tag$, $tag$2026-02-11 09:54:02+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:42:01.563441+00$tag$, 10, 10, 10, 2, 9, 10, $tag$968e0da1-8924-4754-84f5-ccc1cf98dace$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
