INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$33f1a8cd-2324-4f03-b895-657754956235$tag$, $tag$2026021100254$tag$, $tag$Matheus Costa Araújo (5583996656845)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia EAD e quero mais informações.","time":"11/02/2026 11:19:22"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"11/02/2026 11:19:23"},{"role":"client","text":"??","time":"11/02/2026 15:24:28"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"11/02/2026 20:29:53"},{"role":"agent","text":"*Karina Pimentel:* Teologia EAD\n\n A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.\n\nTodas as atividades serão realizadas dentro da plataforma educacional, assim, *não é necessário* ter um Polo da Faculdade em sua cidade.\n\n  Segue a matriz curricular do curso de Teologia *bit.ly/3xljQgl*\n\n🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom BOLSA10\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"11/02/2026 20:30:24","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Já tem a data de início?","time":"11/02/2026 20:33:23"},{"role":"client","text":"Fixa, no caso...","time":"11/02/2026 20:33:29"},{"role":"client","text":"Bom dia","time":"12/02/2026 07:32:23"},{"role":"client","text":"Como finalizo minha matrícula?","time":"12/02/2026 07:32:32"},{"role":"agent","text":"*Karina Pimentel:* Bom dia!","time":"12/02/2026 08:16:33","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Começou dia 02/02, mais as aulas são gravadas e o vai seguir o cronograma que será enviado para o senhor!","time":"12/02/2026 08:17:01","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Jóia!","time":"12/02/2026 08:17:22"},{"role":"client","text":"Como sigo com minha matrícula?","time":"12/02/2026 08:17:29"},{"role":"client","text":"Ela é feita de forma presencial? Preciso ir até a faculdade?","time":"12/02/2026 08:17:53"},{"role":"agent","text":"*Karina Pimentel:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nPara realizar a matrícula escolha de acordo com a sua forma de ingresso:\n\n1 - Aproveitamento do ENEM\n\n2 - Vestibular Agendado: (Será uma redação)\nhttps://bit.ly/VestibularDigitalFICV\n\n3 - Seleção de Graduados\n\n📌 Realize sua matrícula no link:https://bit.ly/SejaFICV\nNa opção \"Sou interessado\"\n\n📝 Após preencher seus dados, você receberá 2 e-mails, um com o Pagamento da primeira parcela e o outro com o Contrato Educacional para sua assinatura eletrônica.","time":"12/02/2026 08:18:02","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Minha nota do Enem é de 2013, dá certo?","time":"12/02/2026 08:18:49"},{"role":"client","text":"Caso não, posso fazer o vestibular, sem problemas!","time":"12/02/2026 08:18:59"},{"role":"agent","text":"*Karina Pimentel:* Enem de até 5 anos. E a nota mínima de 450!","time":"12/02/2026 08:20:48","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Nesse caso, será redação então","time":"12/02/2026 08:21:12"},{"role":"client","text":"Agendo por este link que você enviou?","time":"12/02/2026 08:21:30"},{"role":"agent","text":"*Karina Pimentel:* Isso, vestibular será uma simples redação!","time":"12/02/2026 08:21:51","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/698db7e9ecae5faf2a002384)","time":"12/02/2026 08:22:17"},{"role":"client","text":"O link infelizmente não abre!","time":"12/02/2026 08:22:22"},{"role":"agent","text":"*Karina Pimentel:* https://bit.ly/VestibularDigitalFICV","time":"12/02/2026 08:23:30","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Cai na mesma tela","time":"12/02/2026 08:24:41"},{"role":"client","text":"Tento abrir no notebook pra ver?","time":"12/02/2026 08:24:51"},{"role":"agent","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/vie